oxy_webhelp_navlinks = {"data_transfer_mechanisms_oracle-d30753e31869":{"topics":[{"title":"Enabling secure thrift on the Rubrik cluster using REST APIs","shortdesc":"<p class=\"shortdesc\">To securely transfer data between the Rubrik cluster and the Oracle host, enable the         secure thrift data transfer mechanism for Oracle databases using Rubrik REST         APIs.<\/p>","href":"oracle\/enabling_secure_thrift_using_rest_apis.html","attributes":{"data-id":"enabling_secure_thrift_using_rest_apis"},"menu":{"hasChildren":false},"tocID":"enabling_secure_thrift_using_rest_apis-d30753e31880","topics":[]},{"title":"Secure thrift clone and restore parameter recommendations","shortdesc":"<p class=\"shortdesc\">When you are using secure thrift, Oracle recommends a set of values for the spfile         parameters on your Oracle database to improve performance during a clone         operation.<\/p>","href":"oracle\/secure_thrift_clone_restore_param.html","attributes":{"data-id":"secure_thrift_clone_restore_param"},"menu":{"hasChildren":false},"tocID":"secure_thrift_clone_restore_param-d30753e31891","topics":[]}]}};